import{_ as i,o as r,c as t,ai as o}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Transcript Hygiene","description":"","frontmatter":{"summary":"Reference: provider-specific transcript sanitization and repair rules","read_when":["You are debugging provider request rejections tied to transcript shape","You are changing transcript sanitization or tool-call repair logic","You are investigating tool-call id mismatches across providers"],"title":"Transcript Hygiene"},"headers":[],"relativePath":"reference/transcript-hygiene.md","filePath":"reference/transcript-hygiene.md","lastUpdated":null}'),n={name:"reference/transcript-hygiene.md"};function a(s,e,l,d,c,p){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="transcript-hygiene-provider-fixups" tabindex="-1"><a class="header-anchor" href="#transcript-hygiene-provider-fixups">#</a> Transcript Hygiene (Provider Fixups)</h1><p>This document describes <strong>provider-specific fixes</strong> applied to transcripts before a run (building model context). These are <strong>in-memory</strong> adjustments used to satisfy strict provider requirements. These hygiene steps do <strong>not</strong> rewrite the stored JSONL transcript on disk; however, a separate session-file repair pass may rewrite malformed JSONL files by dropping invalid lines before the session is loaded. When a repair occurs, the original file is backed up alongside the session file.</p><p>Scope includes:</p><ul><li>Tool call id sanitization</li><li>Tool call input validation</li><li>Tool result pairing repair</li><li>Turn validation / ordering</li><li>Thought signature cleanup</li><li>Image payload sanitization</li></ul><p>If you need transcript storage details, see:</p><ul><li><a href="/docs/reference/session-management-compaction">/reference/session-management-compaction</a></li></ul><hr><h2 id="where-this-runs" tabindex="-1"><a class="header-anchor" href="#where-this-runs">#</a> Where this runs</h2><p>All transcript hygiene is centralized in the embedded runner:</p><ul><li>Policy selection: <code>src/agents/transcript-policy.ts</code></li><li>Sanitization/repair application: <code>sanitizeSessionHistory</code> in <code>src/agents/pi-embedded-runner/google.ts</code></li></ul><p>The policy uses <code>provider</code>, <code>modelApi</code>, and <code>modelId</code> to decide what to apply.</p><p>Separate from transcript hygiene, session files are repaired (if needed) before load:</p><ul><li><code>repairSessionFileIfNeeded</code> in <code>src/agents/session-file-repair.ts</code></li><li>Called from <code>run/attempt.ts</code> and <code>compact.ts</code> (embedded runner)</li></ul><hr><h2 id="global-rule-image-sanitization" tabindex="-1"><a class="header-anchor" href="#global-rule-image-sanitization">#</a> Global rule: image sanitization</h2><p>Image payloads are always sanitized to prevent provider-side rejection due to size limits (downscale/recompress oversized base64 images).</p><p>Implementation:</p><ul><li><code>sanitizeSessionMessagesImages</code> in <code>src/agents/pi-embedded-helpers/images.ts</code></li><li><code>sanitizeContentBlocksImages</code> in <code>src/agents/tool-images.ts</code></li></ul><hr><h2 id="global-rule-malformed-tool-calls" tabindex="-1"><a class="header-anchor" href="#global-rule-malformed-tool-calls">#</a> Global rule: malformed tool calls</h2><p>Assistant tool-call blocks that are missing both <code>input</code> and <code>arguments</code> are dropped before model context is built. This prevents provider rejections from partially persisted tool calls (for example, after a rate limit failure).</p><p>Implementation:</p><ul><li><code>sanitizeToolCallInputs</code> in <code>src/agents/session-transcript-repair.ts</code></li><li>Applied in <code>sanitizeSessionHistory</code> in <code>src/agents/pi-embedded-runner/google.ts</code></li></ul><hr><h2 id="provider-matrix-current-behavior" tabindex="-1"><a class="header-anchor" href="#provider-matrix-current-behavior">#</a> Provider matrix (current behavior)</h2><p><strong>OpenAI / OpenAI Codex</strong></p><ul><li>Image sanitization only.</li><li>On model switch into OpenAI Responses/Codex, drop orphaned reasoning signatures (standalone reasoning items without a following content block).</li><li>No tool call id sanitization.</li><li>No tool result pairing repair.</li><li>No turn validation or reordering.</li><li>No synthetic tool results.</li><li>No thought signature stripping.</li></ul><p><strong>Google (Generative AI / Gemini CLI / Antigravity)</strong></p><ul><li>Tool call id sanitization: strict alphanumeric.</li><li>Tool result pairing repair and synthetic tool results.</li><li>Turn validation (Gemini-style turn alternation).</li><li>Google turn ordering fixup (prepend a tiny user bootstrap if history starts with assistant).</li><li>Antigravity Claude: normalize thinking signatures; drop unsigned thinking blocks.</li></ul><p><strong>Anthropic / Minimax (Anthropic-compatible)</strong></p><ul><li>Tool result pairing repair and synthetic tool results.</li><li>Turn validation (merge consecutive user turns to satisfy strict alternation).</li></ul><p><strong>Mistral (including model-id based detection)</strong></p><ul><li>Tool call id sanitization: strict9 (alphanumeric length 9).</li></ul><p><strong>OpenRouter Gemini</strong></p><ul><li>Thought signature cleanup: strip non-base64 <code>thought_signature</code> values (keep base64).</li></ul><p><strong>Everything else</strong></p><ul><li>Image sanitization only.</li></ul><hr><h2 id="historical-behavior-pre-2026-1-22" tabindex="-1"><a class="header-anchor" href="#historical-behavior-pre-2026-1-22">#</a> Historical behavior (pre-2026.1.22)</h2><p>Before the 2026.1.22 release, OpenSoul applied multiple layers of transcript hygiene:</p><ul><li>A <strong>transcript-sanitize extension</strong> ran on every context build and could: <ul><li>Repair tool use/result pairing.</li><li>Sanitize tool call ids (including a non-strict mode that preserved <code>_</code>/<code>-</code>).</li></ul></li><li>The runner also performed provider-specific sanitization, which duplicated work.</li><li>Additional mutations occurred outside the provider policy, including: <ul><li>Stripping <code>&lt;final&gt;</code> tags from assistant text before persistence.</li><li>Dropping empty assistant error turns.</li><li>Trimming assistant content after tool calls.</li></ul></li></ul><p>This complexity caused cross-provider regressions (notably <code>openai-responses</code><code>call_id|fc_id</code> pairing). The 2026.1.22 cleanup removed the extension, centralized logic in the runner, and made OpenAI <strong>no-touch</strong> beyond image sanitization.</p>',42)])])}const h=i(n,[["render",a]]);export{g as __pageData,h as default};
